using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents and raw SQL queries still work.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change: id no longer prefixed with discriminator.
            // Existing documents use "Blog|{key}" format; preserve it via value converter.
            entity.Property(b => b.Id)
                .HasConversion(
                    id => "Blog|" + id,
                    id => id.Substring(id.IndexOf('|') + 1));

            // Breaking change: HasIndex() now throws for the Cosmos provider.
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

